import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Select, Badge, icon } from 'decantr/components';

code.example:
function ProductGrid({ products = [], categories = [] }) {
  const { div, span, img, p, h3 } = tags;
  const [view, setView] = createSignal('grid');
  const [category, setCategory] = createSignal('all');
  const [sort, setSort] = createSignal('newest');
  const [type, setType] = createSignal('all');

  const filtered = () => {
    let items = products;
    if (category() !== 'all') items = items.filter(p => p.category === category());
    if (type() !== 'all') items = items.filter(p => p.type === type());
    return items.sort((a, b) => {
      if (sort() === 'newest') return new Date(b.createdAt) - new Date(a.createdAt);
      if (sort() === 'price-low') return a.price - b.price;
      if (sort() === 'price-high') return b.price - a.price;
      if (sort() === 'popular') return b.likes - a.likes;
      return 0;
    });
  };

  const typeIcon = { image: 'image', video: 'video', audio: 'music', document: 'file-text', all: 'grid' };

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _gap4 _aic _jcsb _flexwrap') },
      div({ class: css('_flex _gap3 _aic _flexwrap') },
        Select({ value: category(), onchange: (e) => setCategory(e.target.value), options: [
          { value: 'all', label: 'All Categories' },
          ...categories.map(c => ({ value: c.id, label: c.name }))
        ]}),
        div({ class: css('_flex _bgmuted/10 _r2 _p1') },
          ...['all', 'image', 'video', 'audio', 'document'].map(t =>
            Button({
              variant: type() === t ? 'primary' : 'ghost',
              size: 'sm',
              onclick: () => setType(t)
            }, icon(typeIcon[t], { size: '16' }))
          )
        )
      ),
      div({ class: css('_flex _gap2 _aic') },
        Select({ value: sort(), onchange: (e) => setSort(e.target.value), options: [
          { value: 'newest', label: 'Newest' },
          { value: 'price-low', label: 'Price: Low to High' },
          { value: 'price-high', label: 'Price: High to Low' },
          { value: 'popular', label: 'Most Popular' }
        ]}),
        div({ class: css('_flex _bgmuted/10 _r2 _p1') },
          Button({ variant: view() === 'grid' ? 'primary' : 'ghost', size: 'sm', onclick: () => setView('grid') }, icon('grid', { size: '16' })),
          Button({ variant: view() === 'list' ? 'primary' : 'ghost', size: 'sm', onclick: () => setView('list') }, icon('list', { size: '16' }))
        )
      )
    ),
    filtered().length > 0 ? div({ class: css(view() === 'grid' ? '_grid _gc2 _md:gc3 _lg:gc4 _gap4' : '_flex _col _gap3') },
      ...filtered().map(product =>
        view() === 'grid' ? Card({ class: css('studio-card _overflow[hidden] _trans _hover:shadow _cursor[pointer]') },
          div({ class: css('_relative _aspect[16/9] _bgmuted/10') },
            product.thumbnail ? img({ src: product.thumbnail, class: css('_wfull _hfull _objcover') }) :
              div({ class: css('_flex _center _hfull') }, icon(typeIcon[product.type] || 'file', { size: '32', class: css('_fgmuted') })),
            product.locked ? div({ class: css('_absolute _inset0 _bg[rgba(0,0,0,0.3)] _flex _center') },
              icon('lock', { size: '24', class: css('_text[white]') })
            ) : null,
            product.type === 'video' ? div({ class: css('_absolute _bottom2 _right2 _px2 _py1 _r1 _bg[rgba(0,0,0,0.7)] _text[white] _textxs') },
              product.duration
            ) : null
          ),
          div({ class: css('_p4') },
            h3({ class: css('_fontmedium _truncate _mb1') }, product.title),
            div({ class: css('_flex _jcsb _aic') },
              product.price > 0 ? span({ class: css('_fontmedium _fgPrimary') }, '$', product.price) :
                Badge({ variant: 'secondary', size: 'sm' }, product.tierName || 'Free'),
              div({ class: css('_flex _aic _gap1 _textsm _fgmuted') },
                icon('heart', { size: '14' }), product.likes || 0
              )
            )
          )
        ) : Card({ class: css('studio-card _p4 _flex _gap4 _cursor[pointer]') },
          div({ class: css('_w24 _h16 _r2 _overflow[hidden] _bgmuted/10 _flex-shrink-0') },
            product.thumbnail ? img({ src: product.thumbnail, class: css('_wfull _hfull _objcover') }) :
              div({ class: css('_flex _center _hfull') }, icon(typeIcon[product.type], { size: '24', class: css('_fgmuted') }))
          ),
          div({ class: css('_flex1') },
            h3({ class: css('_fontmedium _mb1') }, product.title),
            p({ class: css('_textsm _fgmuted _lineClamp2') }, product.description)
          ),
          div({ class: css('_flex _col _aic') },
            product.price > 0 ? span({ class: css('_fontmedium _fgPrimary') }, '$', product.price) :
              Badge({ variant: 'secondary' }, product.tierName || 'Free')
          )
        )
      )
    ) : div({ class: css('_py16 _tc _fgmuted') },
      icon('inbox', { size: '48', class: css('_mb4 _fgmuted/50') }),
      p({}, 'No products found')
    ),
    filtered().length > 12 ? div({ class: css('_flex _jcc _mt4') },
      Button({ variant: 'outline' }, 'Load More')
    ) : null
  );
}

