function ProductList({ products }) {
  const { div, img, h3, p, span } = tags;

  return div({ class: css('_flex _col _gap3') },
    ...products.map(product =>
      Card({ class: css('studio-card _p4 _flex _gap4') },
        div({ class: css('_w20 _h14 _r2 _overflow[hidden] _bgmuted/10') },
          product.thumbnail ? img({ src: product.thumbnail, class: css('_wfull _hfull _objcover') }) : null
        ),
        div({ class: css('_flex1') },
          h3({ class: css('_fontmedium') }, product.title),
          p({ class: css('_textsm _fgmuted') }, product.description)
        ),
        span({ class: css('_fontmedium') }, '$', product.price)
      )
    )
  );
}

