function MasonryProductGrid({ products }) {
  const { div, img, h3, span } = tags;

  return div({ class: css('_columns2 _md:columns3 _gap4') },
    ...products.map(product =>
      Card({ class: css('studio-card _overflow[hidden] _mb4 _breakInside[avoid]') },
        product.thumbnail ? img({ src: product.thumbnail, class: css('_wfull') }) : null,
        div({ class: css('_p4') },
          h3({ class: css('_fontmedium') }, product.title),
          span({ class: css('_fgPrimary') }, '$', product.price)
        )
      )
    )
  );
}

